<?php namespace App\Exceptions; use Illuminate\Foundation\Exceptions\Handler as ExceptionHandler; use Illuminate\Http\Request; use Illuminate\Validation\ValidationException; use Symfony\Component\HttpKernel\Exception\HttpExceptionInterface; use Throwable; use Illuminate\Support\Facades\Log; class ErrorHandler extends ExceptionHandler { public function register(): void { $this->renderable(function (Throwable $e, Request $request) { if ($request->is('api/*')) { return $this->handleApiException($e); } }); } private function handleApiException(Throwable $e) { $status = 500; $message = 'حدث خطأ غير متوقع في الخادم'; $errors = []; if ($e instanceof ValidationException) { $status = 422; $message = 'خطأ في التحقق من البيانات'; $errors = $e->errors(); } elseif ($e instanceof HttpExceptionInterface) { $status = $e->getStatusCode(); $message = $e->getMessage() ?: 'خطأ في الطلب'; } if ($status >= 500) { Log::critical('Critical Error Occurred: ' . $e->getMessage(), ['trace' => $e->getTraceAsString()]); } return response()->json([ 'status' => $status, 'message' => $message, 'errors' => $errors ], $status); } }